INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (1, 1, 'Chào hỏi cơ bản', 'chao-hoi-co-ban', '# Chào hỏi cơ bản\n\n## Mục tiêu\n- Chào buổi sáng / chiều / tối\n- Tự giới thiệu tên\n\n## Hội thoại mẫu\n> A: おはようございます。\n> B: おはようございます。\n\n## Lưu ý\nDùng **です／ます** trong ngữ cảnh lịch sự.', 1, 15, false, true, '2026-03-16T07:55:09.6547085', '2026-03-16T07:55:09.6547085', 1);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (2, 1, 'Số đếm 1-10', 'so-dem-1-10', '# Số đếm cơ bản\n\nいち(1), に(2), さん(3), し/よん(4), ご(5), ろく(6), なな/しち(7), はち(8), きゅう(9), じゅう(10)', 2, 15, false, true, '2026-03-16T07:55:09.6547085', '2026-03-16T07:55:09.6547085', 1);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (3, 2, 'です - Câu khẳng định', 'desu-cau-khang-dinh', '# Mẫu câu です\n\nDanh từ + です = "là..."\n\n- 私は学生です。(Tôi là học sinh.)\n- これは本です。(Đây là sách.)', 1, 12, false, true, '2026-03-16T07:55:09.6547085', '2026-03-16T07:55:09.6547085', 1);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (4, 3, 'Kanji cơ bản 1', 'kanji-co-ban-1', '# Nhân, Nhật, Mộc, Thủy, Hỏa\n\n人(người), 日(nhật/ngày), 木(cây), 水(nước), 火(lửa)', 1, 20, false, true, '2026-03-16T07:55:09.6547085', '2026-03-16T07:55:09.6547085', 1);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (5, 4, 'Từ vựng gia đình N4', 'tu-vung-gia-dinh-n4', '# Gia đình\n\n家族、父、母、兄、姉、弟、妹', 1, 15, false, true, '2026-03-16T07:55:09.6547085', '2026-03-16T07:55:09.6547085', 1);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (7, 1, 'HIRAGANA', 'HIRAGANA', '<p>あ</p>', 6, 10, false, true, '2026-03-28T17:01:54.5156183', '2026-03-28T17:01:54.5156183', 29);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (11, 1, 'UNIT 2.1', 'UNIT 2.1', '<p>パソコン</p>', 4, 10, false, true, '2026-04-07T06:00:01.0105915', '2026-04-07T06:00:01.0888665', 29);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (12, 3, 'Giáo trình tiếng Nhật - Thể số cơ bản', 'thi-thu-tong-trieu-nhat-the-so-co-ban', '<p><strong>見る</strong>（みる）— xem, nhìn</p><p><strong>勉強</strong></p><p><strong>へんきょう</strong></p><p>học, ôn bài</p>', 2, 30, false, false, '2026-04-07T06:00:01.0105915', '2026-04-07T06:00:01.0888665', 29);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (13, 3, 'Giới thiệu về lịch tiếng Nhật', 'gioi-thi-hu-ve-lich-tieng-jp', '<p><strong>日曜日</strong>（にちようび）— ngày thứ 7 trong tuần, thường được sử dụng để chỉ cuối tuần</p>', 3, 15, false, true, '2026-04-07T06:00:01.0105915', '2026-04-07T06:00:01.0888665', 29);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (14, 3, 'Giải thích từ ''千'' trong tiếng Nhật', 'giai-thich-tu-kyu-n-dong-trong-tieng-nhat', '<p>千 (kyū) là một từ đơn của tiếng Nhật có nghĩa là nghìn hoặc ngàn. Nó thường được sử dụng để chỉ các số lượng lớn trong các tình huống khác nhau.</p><p>Trong ví dụ trên, từ ''千'' được sử dụng để chỉ các đơn vị đo lường như円 (vạn đồng), ngàn, vạn, triệu, triệu, tỷ, triệu, tỷ, ngàn, ngàn, vạn, vạn, ngàn, ngàn, vạn, vạn, ngàn.</p><p>Tên gọi tắt của từ ''千'' là sen</p><p>Trong tiếng Nhật, mỗi số lượng lớn đều có một cách gọi riêng và từ ''sen'' được sử dụng để chỉ các đơn vị đo lường như 円 (vạn đồng), ngàn, vạn, triệu, triệu, tỷ, triệu, tỷ, ngàn, ngàn, vạn, vạn, ngàn.</p><p>Tên gọi tắt của từ ''ken'' là ken</p><p>Trong tiếng Nhật, mỗi số lượng lớn đều có một cách gọi riêng và từ ''ken'' được sử dụng để chỉ các đơn vị đo lường như SEN (ngàn), SEN (vạn)</p><p>Mỗi chữ ''sen'', ''ken'' đều có một cách gọi khác là sen-zen và ken-zen</p><p>Trong tiếng Nhật, mỗi số lượng lớn đều có một cách gọi riêng.</p>', 4, 15, false, true, '2026-04-07T06:38:01.3035171', '2026-04-07T06:38:01.3800451', 29);
INSERT INTO "lessons" ("id", "category_id", "title", "slug", "content", "sort_order", "estimated_minutes", "is_premium", "is_published", "created_at", "updated_at", "created_by") VALUES (15, 1, 'Bảng chữ hiragana', 'bang-chu-hiragana', '<p><strong>み</strong></p><p>mi</p><p>Một kana đọc là âm tương ứng của chữ Nhật gốc.</p>', 5, 10, false, true, '2026-04-07T07:40:08.4120960', '2026-04-07T07:40:08.4939629', 29);
